WebLink.url:
/** /flow/UpdateBizCard?recordId={!Sansan_CI__BizCard__c.Id} */

{!REQUIRESCRIPT("/soap/ajax/38.0/connection.js")}
{!REQUIRESCRIPT("/soap/ajax/38.0/apex.js")}

var record = "{!Sansan_CI__BizCard__c.Id}";

var result = window.confirm('選択した名刺を振分け対象外にします。');
if( result ) {
	var objs = [];
	var obj = new sforce.SObject('Sansan_CI__BizCard__c');
	obj.id = record;
	obj.Sansan_CI__IsNotDistribution__c = "true";
	objs.push(obj);
	var results = sforce.connection.update(objs);
	window.location.reload();

}
